function solve(n, edges) {
  // Build adjacency list
  const adj = new Array(n).fill().map(() => []);
  for (const [u, v, s, e] of edges) {
    adj[u].push([v, s, e]);
  }

  // Dijkstra's algorithm
  const dist = new Array(n).fill(Infinity);
  dist[0] = 0;

  class PriorityQueue {
    constructor() {
      this.heap = [];
    }
    push(value) {
      this.heap.push(value);
      this.heapifyUp(this.heap.length - 1);
    }
    pop() {
      if (this.heap.length === 0) return null;
      const min = this.heap[0];
      this.heap[0] = this.heap.pop();
      this.heapifyDown(0);
      return min;
    }
    heapifyUp(index) {
      while (index > 0) {
        const parentIndex = Math.floor((index - 1) / 2);
        if (this.heap[parentIndex][0] <= this.heap[index][0]) break;
        [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
        index = parentIndex;
      }
    }
    heapifyDown(index) {
      const n = this.heap.length;
      while (index < n) {
        const left = 2 * index + 1;
        const right = 2 * index + 2;
        let smallest = index;
        if (left < n && this.heap[left][0] < this.heap[smallest][0]) smallest = left;
        if (right < n && this.heap[right][0] < this.heap[smallest][0]) smallest = right;
        if (smallest === index) break;
        [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
        index = smallest;
      }
    }
    getSize() {
      return this.heap.length;
    }
  }

  const pq = new PriorityQueue();
  pq.push([0, 0]);

  while (pq.getSize() > 0) {
    const [currentTime, u] = pq.pop();
    if (u === n - 1) return currentTime;
    if (currentTime > dist[u]) continue;
    for (const [v, s, e] of adj[u]) {
      const earliest = Math.max(currentTime, s);
      if (earliest > e) continue;
      const newTime = earliest + 1;
      if (newTime < dist[v]) {
        dist[v] = newTime;
        pq.push([newTime, v]);
      }
    }
  }

  return -1;
}

